import{c as o,a3 as t,p as a,s as c}from"./chunks/framework.BEQTiVti.js";const u=JSON.parse('{"title":"📠 Change Log","description":"","frontmatter":{},"headers":[],"relativePath":"en-US/guide/changelog.md","filePath":"en-US/guide/changelog.md","lastUpdated":1780498940000}'),d={name:"en-US/guide/changelog.md"};function i(n,e,r,l,s,h){return t(),a("div",null,[...e[0]||(e[0]=[c('<h1 id="📠-change-log" tabindex="-1">📠 Change Log <a class="header-anchor" href="#📠-change-log" aria-label="Permalink to “📠 Change Log”">​</a></h1><h2 id="_10-0-0-beta3" tabindex="-1">10.0.0-beta3 <a class="header-anchor" href="#_10-0-0-beta3" aria-label="Permalink to “10.0.0-beta3”">​</a></h2><p><code>2026-06-03</code></p><ul><li>🆕 Support custom hot keys.</li><li>🆕 A new continuous drawing mode is added to the cover, and a <code>brush</code> is added to the built-in cover.</li><li>👉 Adjust the calculation logic of the built-in indicator <code>RSI</code>.</li><li>🐞 Fix the problem that when the overlay is locked, the event falls on the overlay and the chart cannot be scrolled.</li><li>🐞 Fix the problem that overlays that are forced to end drawing cannot be restored through <code>createOverlay</code>.</li><li>🐞 Fix the issue of drawing response in overlay field weakening mode.</li><li>🐞 Fix an issue where data request method callbacks may be triggered infinitely when loading data backwards.</li><li>🐞 Fix the problem that <code>resize</code> may not take effect.</li></ul><h2 id="_10-0-0-beta2" tabindex="-1">10.0.0-beta2 <a class="header-anchor" href="#_10-0-0-beta2" aria-label="Permalink to “10.0.0-beta2”">​</a></h2><p><code>2026-05-20</code></p><ul><li><p>🆕 New Features</p><ul><li>Support multiple y-axes. Multiple y-axes can be created in the same pane, and indicators can be bound to a specified y-axis through <code>yAxisId</code>.</li><li>Add instance methods <code>overrideXAxis(options)</code> and <code>overrideYAxis(options)</code> for independently configuring the x-axis and y-axis.</li><li>The chart now supports automatically listening to container size changes and calling <code>resize()</code>.</li><li>Add the <code>text</code> type to indicator figures, allowing indicator <code>figures</code> to draw text directly.</li></ul></li><li><p>👉 Changes</p><ul><li>In the chart method <code>init(ds, options)</code>, <code>options.layout</code> has been changed from an array structure to an object structure, with <code>basicParams</code> and <code>panes</code> added: <ul><li><code>basicParams</code> supports configuring <code>barSpaceLimitMin</code>, <code>barSpaceLimitMax</code>, <code>yAxisPosition</code>, <code>yAxisInside</code>, <code>paneMinHeight</code>, and <code>paneHeight</code>.</li><li><code>panes</code> is used to configure pane layout, and pane content supports specifying a y-axis configuration for an indicator through <code>{ indicator, yAxis }</code>.</li></ul></li><li>The instance method <code>createIndicator(indicator, isStack?, paneOptions?)</code> has been changed to <code>createIndicator(indicator, options?)</code>, and <code>options</code> supports <code>isStack</code>, <code>pane</code>, and <code>yAxis</code>.</li><li><code>setPaneOptions(options)</code> no longer includes axis configuration. Use <code>overrideXAxis(options)</code> or <code>overrideYAxis(options)</code> for axis configuration.</li><li>Add <code>yAxisId</code> to the <code>filter</code> parameter of <code>convertToPixel(value, filter?)</code> and <code>convertFromPixel(coordinate, filter?)</code>.</li></ul></li><li><p>🐞 Fixed the parameter type error of the instance API <code>setZoomAnchor</code>.</p></li><li><p>💄 Optimized the build process. The build tool has been changed from rollup to Vite, and <code>type-check</code> has been added.</p></li></ul><h2 id="_10-0-0-beta1" tabindex="-1">10.0.0-beta1 <a class="header-anchor" href="#_10-0-0-beta1" aria-label="Permalink to “10.0.0-beta1”">​</a></h2><p><code>2025-11-21</code></p><ul><li><p>🆕 New Features</p><ul><li>Support thousands separators and custom decimal collapse.</li><li>Support displaying future time on the x-axis.</li><li>Support dragging the y-axis on mobile devices.</li><li>Support creating multiple metrics with the same name on the same window.</li><li>Rewrote the axis module; custom y-axis supports setting the range.</li><li>Add <code>zoomAnchor</code> to the <code>options</code> method of the chart method <code>init(dom, options)</code>.</li><li>New instance methods <code>setZoomAnchor(anchor)</code>, <code>getZoomAnchor()</code>, <code>setDataLoader(loader)</code>, <code>setSymbol(symbol)</code>, <code>getSymbol()</code>, <code>setPeriod(period)</code>, <code>getPeriod()</code>, <code>resetData()</code>, <code>setThousandsSeparator(thousandsSeparator)</code> , <code>getThousandsSeparator()</code> , <code>setDecimalFold(decimalFold)</code> , <code>getDecimalFold()</code> , <code>getIndicators()</code> and <code>getOverlays()</code> .</li><li>Add style configurations: <code>candle.priceMark.last.extendTexts</code>, <code>candle.tooltip.title</code>, <code>candle.tooltip.legend</code>, <code>indicator.tooltip.title</code>, <code>indicator.tooltip.legend</code>, <code>crosshair.horizontal.features</code>, <code>candle.bar.compareRule</code>, <code>indicator.ohlc.compareRule</code>, and <code>candle.priceMark.last.compareRule</code>.</li><li>Add <code>onIndicatorTooltipFeatureClick</code> and <code>onCrosshairFeatureClick</code> to the <code>type</code> parameter in the instance methods <code>subscribeAction</code> and <code>unsubscribeAction</code>.</li></ul></li><li><p>👉 Changes</p><ul><li>In the chart method <code>init(dcs, options)</code>, the <code>position</code> sub-item of <code>options.layout</code> has been changed to <code>order</code>, <code>options.thousandsSeparator</code> has been changed to the object <code>{ sign, format }</code>, <code>options.decimalFoldThreshold</code> has been changed to <code>options.decimalFold</code>, <code>options.customApi</code> has been changed to <code>options.formatter</code>, and the parameter of <code>formatDate</code> has been changed to an object.</li><li>In the instance methods <code>setCustomApi</code> and <code>getCustomApi</code> have been changed to <code>getFormatter</code>, the return value of <code>getBarSpace()</code> has been changed to an object, the return value of <code>createIndicator</code> has been changed to return the indicator ID, and the input parameter <code>paneId</code> of <code>overlayIndicator</code> has been merged into the input parameter <code>indicator</code>.</li><li>The return value of the custom metric <code>createTooltipDataSource</code> method has been changed from <code>values</code> to <code>legends</code>, and <code>icons</code> to <code>features</code>.</li><li>The style configurations <code>candle.tooltip.icons</code> and <code>indicator.tooltip.icons</code> have been changed to <code>indicator.tooltip.features</code>.</li></ul></li><li><p>💄 Optimizations</p><ul><li>Optimized the <code>figure</code> element in the overlay template to ignore event types, ensuring the event name matches the event name in <code>overlay</code>.</li><li>Optimized the execution of metric calculation tasks.</li><li>Optimized the triggering of scroll events on mobile devices.</li></ul></li><li><p>🗑 Deprecated</p><ul><li>The following chart methods have been removed: <code>utils.drawArc(ctx, arc, styles)</code>, <code>utils.drawCircle(ctx, circle, styles)</code>, <code>utils.drawLine(ctx, line, styles)</code>, <code>utils.drawPolygon(ctx, polygon, styles)</code>, <code>utils.drawRect(ctx, rect, styles)</code>, <code>utils.drawText(ctx, text, styles)</code>, <code>utils.drawRectText(ctx, rectText, styles)</code>. Please use <code>getFigureClass(name)</code> instead.</li><li>The following instance method has been removed: <code>setPriceVolumePrecision(pricePrecision, volumePrecision)</code>. Please use <code>setPrecision(precision)</code> instead.</li><li>In the instance API, remove <code>setLoadMoreData</code>, <code>applyNewData</code>, and <code>updateData</code>. Replace them with <code>setDataLoader</code>. Remove <code>clearData</code>, <code>setPrecision</code>, and <code>getPrecision</code>.</li><li>In the instance method, remove <code>getIndicatorByPaneId(paneId, name)</code>. Replace it with <code>getIndicators(filter)</code>.</li><li>In the instance method, remove <code>getOverlayById(id)</code>. Replace it with <code>getOverlays(filter)</code>.</li><li>In the instance methods <code>subscribeAction</code> and <code>unsubscribeAction</code>, remove the parameter <code>onTooltipIconClick</code>. Replace it with <code>onCandleTooltipFeatureClick</code> and <code>onIndicatorTooltipFeatureClick</code>.</li><li>The style configuration removes <code>yAxis.position</code>, <code>yAxis.type</code>, <code>yAxis.inside</code>, and <code>yAxis.inside</code>. Please use <code>[overrideYAxis(options)](/api/instance/overrideYAxis#parameters)</code> instead. For details, see the chart API <code>[init(dcs, options)](/api/chart/init#parameters)</code>, the instance APIs <code>[createIndicator(indicator, options)](/api/instance/createIndicator#parameters)</code>, <code>[setPaneOptions(options)](/api/instance/setPaneOptions#parameters)</code>, and <code>[overrideYAxis(options)](/api/instance/overrideYAxis#parameters)</code>.</li><li>In style configuration, remove <code>candle.tooltip.defaultValue</code> and replace <code>candle.tooltip.custom</code> with <code>candle.tooltip.legend</code>. Also remove <code>candle.tooltip.text</code>, <code>indicator.tooltip.showName</code>, and <code>indicator.tooltip.showParams</code>; use <code>indicator.tooltip.title</code> instead. Remove <code>indicator.tooltip.defaultValue</code> and replace it with <code>indicator.tooltip.legend</code>. Also remove <code>indicator.tooltip.text</code> and <code>overlay.rectText</code>.</li><li>In built-in basic graphics, remove <code>rectText</code> and replace it with <code>text</code>.</li></ul></li></ul><h2 id="_9-x" tabindex="-1">9.x <a class="header-anchor" href="#_9-x" aria-label="Permalink to “9.x”">​</a></h2><p>Go to <a href="https://v9.klinecharts.com" target="_blank" rel="noreferrer">https://v9.klinecharts.com</a> to check the change log for 9.x.</p><h2 id="_8-x" tabindex="-1">8.x <a class="header-anchor" href="#_8-x" aria-label="Permalink to “8.x”">​</a></h2><p>Go to <a href="https://v8.klinecharts.com" target="_blank" rel="noreferrer">https://v8.klinecharts.com</a> to check the change log for 9.x.</p><h2 id="_7-x" tabindex="-1">7.x <a class="header-anchor" href="#_7-x" aria-label="Permalink to “7.x”">​</a></h2><p>Go to <a href="https://github.com/liihuu/KLineChart/blob/v7.5.0/docs/en/changelog.md" target="_blank" rel="noreferrer">Github</a> to check the change log for 7.x.</p><h2 id="_6-x" tabindex="-1">6.x <a class="header-anchor" href="#_6-x" aria-label="Permalink to “6.x”">​</a></h2><p>Go to <a href="https://github.com/liihuu/KLineChart/blob/v6.1.0/docs/en/CHANGELOG.md" target="_blank" rel="noreferrer">Github</a> to check the change log for 6.x.</p><h2 id="_5-x" tabindex="-1">5.x <a class="header-anchor" href="#_5-x" aria-label="Permalink to “5.x”">​</a></h2><p>Go to <a href="https://github.com/liihuu/KLineChart/releases/tag/v5.0.0" target="_blank" rel="noreferrer">Github</a> to view the 5.x release notes.</p><h2 id="_4-x" tabindex="-1">4.x <a class="header-anchor" href="#_4-x" aria-label="Permalink to “4.x”">​</a></h2><p>Go to <a href="https://github.com/liihuu/KLineChart/releases/tag/v4.0.0" target="_blank" rel="noreferrer">Github</a> to view the 4.x release notes.</p>',22)])])}const m=o(d,[["render",i]]);export{u as __pageData,m as default};
